// ============================================================================
// CHECK CONTRACT EXISTS
// ============================================================================

const contract = $('Get Contract Text').first().json;
if (!contract || !contract.extracted_text) {
  throw new Error('Contract not found or has no extracted text');
}

return { json: { contractId: $('Validate Input').first().json.contractId, status: 'processing' } };

// ============================================================================
// PREPARE SCHEDULE DETECTION PROMPT
// Builds claudeRequestBody for the HTTP Request node (Anthropic Messages API)
// ============================================================================

const contract = $('Get Contract Text').first().json;
const contractTypeKey = $('Validate Input').first().json.contractTypeKey || contract.contract_type_key || 'service_agreement';

// Expected schedules by contract type
const SCHEDULE_EXPECTATIONS = {
  bpo_agreement: [
    { type: 'scope_of_work', label: 'Scope of Work / Statement of Work', required: true },
    { type: 'pricing', label: 'Pricing Schedule / Rate Card', required: true },
    { type: 'service_levels', label: 'Service Level Agreement / SLA', required: true },
    { type: 'data_processing', label: 'Data Processing Agreement / DPA', required: true },
    { type: 'governance', label: 'Governance Schedule', required: true },
    { type: 'exit_transition', label: 'Exit & Transition Plan', required: true },
    { type: 'disaster_recovery', label: 'Disaster Recovery / Business Continuity', required: true },
    { type: 'change_control', label: 'Change Control Procedure', required: false },
    { type: 'insurance', label: 'Insurance Schedule', required: false },
    { type: 'benchmarking', label: 'Benchmarking Schedule', required: false },
    { type: 'subcontracting', label: 'Approved Subcontractors', required: false },
  ],
  it_outsourcing: [
    { type: 'scope_of_work', label: 'Scope of Work', required: true },
    { type: 'pricing', label: 'Pricing Schedule', required: true },
    { type: 'service_levels', label: 'Service Level Agreement', required: true },
    { type: 'data_processing', label: 'Data Processing Agreement', required: true },
    { type: 'exit_transition', label: 'Exit & Transition Plan', required: true },
    { type: 'disaster_recovery', label: 'Disaster Recovery', required: true },
    { type: 'governance', label: 'Governance Schedule', required: false },
    { type: 'security', label: 'Security Schedule', required: false },
    { type: 'change_control', label: 'Change Control', required: false },
  ],
  managed_services: [
    { type: 'scope_of_work', label: 'Scope of Work', required: true },
    { type: 'pricing', label: 'Pricing Schedule', required: true },
    { type: 'service_levels', label: 'Service Level Agreement', required: true },
    { type: 'data_processing', label: 'Data Processing Agreement', required: false },
    { type: 'governance', label: 'Governance Schedule', required: false },
    { type: 'exit_transition', label: 'Exit & Transition Plan', required: false },
    { type: 'change_control', label: 'Change Control', required: false },
  ],
  service_agreement: [
    { type: 'scope_of_work', label: 'Scope of Work', required: false },
    { type: 'pricing', label: 'Pricing Schedule', required: false },
    { type: 'service_levels', label: 'Service Level Agreement', required: false },
    { type: 'data_processing', label: 'Data Processing Agreement', required: false },
    { type: 'insurance', label: 'Insurance Schedule', required: false },
  ],
  saas_agreement: [
    { type: 'service_levels', label: 'Service Level Agreement', required: true },
    { type: 'data_processing', label: 'Data Processing Agreement', required: true },
    { type: 'pricing', label: 'Pricing / Subscription Terms', required: false },
    { type: 'security', label: 'Security Schedule', required: false },
    { type: 'disaster_recovery', label: 'Disaster Recovery', required: false },
  ],
  consultancy_agreement: [
    { type: 'scope_of_work', label: 'Scope of Work / Statement of Work', required: false },
    { type: 'pricing', label: 'Fee Schedule', required: false },
  ],
  maintenance_agreement: [
    { type: 'service_levels', label: 'Service Level Agreement', required: false },
    { type: 'pricing', label: 'Pricing Schedule', required: false },
  ],
};

const expectedSchedules = SCHEDULE_EXPECTATIONS[contractTypeKey] || SCHEDULE_EXPECTATIONS['service_agreement'];

const expectedListText = expectedSchedules.map(s =>
  `- ${s.label} (type: ${s.type}) ${s.required ? '[REQUIRED]' : '[OPTIONAL]'}`
).join('\n');

// Limit text to avoid exceeding context window
const MAX_CHARS = 120000;
let text = contract.extracted_text;
if (text.length > MAX_CHARS) {
  text = text.substring(0, MAX_CHARS) + '\n\n[TEXT TRUNCATED AT ' + MAX_CHARS + ' CHARACTERS]';
}

const systemPrompt = `You are CLARENCE — a contract analysis engine specialising in identifying contract schedules, appendices, and annexes.

YOUR TASK: Identify ALL schedules, appendices, annexes, and attachments in this contract document.

SCHEDULES are separate sections typically found after the main body of a contract. They contain operational, commercial, or technical details such as:
- Scope of Work / Statement of Work (deliverables, milestones)
- Pricing / Rate Cards (fees, indexation, payment mechanics)
- Service Level Agreements (SLA targets, KPIs, service credits)
- Data Processing Agreements (GDPR, sub-processors, data handling)
- Governance (steering committees, reporting, escalation)
- Exit & Transition Plans (handover, knowledge transfer, data migration)
- Insurance (coverage requirements)
- Change Control (change request procedures)
- Disaster Recovery / Business Continuity
- Security Requirements
- Benchmarking
- Approved Subcontractors

SCHEDULE DETECTION RULES:
1. Look for headings like "Schedule", "Appendix", "Annex", "Attachment", "Exhibit", "Addendum"
2. Also identify sections that function as schedules even if not formally labelled (e.g. a pricing table within a section)
3. Classify each detected schedule into the correct schedule_type
4. Note the approximate character position where each schedule starts and ends
5. Provide a brief summary of what each schedule covers

VALID SCHEDULE TYPES:
scope_of_work, pricing, service_levels, data_processing, governance, exit_transition, insurance, change_control, disaster_recovery, security, benchmarking, subcontracting, other

OUTPUT FORMAT — return ONLY valid JSON (no markdown backticks):

{
  "detected_schedules": [
    {
      "schedule_type": "service_levels",
      "schedule_label": "Schedule 3 - Service Levels",
      "start_char": 45000,
      "end_char": 52000,
      "confidence": 0.95,
      "summary": "Defines uptime SLA targets (99.5%), response time KPIs, service credit calculation methodology, and measurement periods."
    }
  ],
  "missing_expected": [
    {
      "schedule_type": "exit_transition",
      "schedule_label": "Exit & Transition Plan",
      "is_required": true,
      "reason": "No exit or transition provisions found in any schedule or appendix."
    }
  ],
  "detection_summary": "Found 5 schedules. 2 required schedules are missing."
}`;

const userPrompt = `Analyse this ${contract.detected_contract_type || contractTypeKey} contract and identify ALL schedules, appendices, and annexes.

CONTRACT: ${contract.contract_name || 'Unnamed Contract'}
CONTRACT TYPE: ${contractTypeKey}

EXPECTED SCHEDULES FOR THIS CONTRACT TYPE:
${expectedListText}

---
${text}
---

Identify every schedule/appendix/annex. For each, classify its type, note its position in the document, and provide a brief summary. Also flag any EXPECTED schedules that are MISSING.

Return ONLY the JSON object.`;

// Build the Anthropic Messages API request body
const claudeRequestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 8000,
  temperature: 0,
  system: systemPrompt,
  messages: [
    { role: 'user', content: userPrompt }
  ]
};

return {
  json: {
    contractId: $('Validate Input').first().json.contractId,
    contractTypeKey,
    contractName: contract.contract_name,
    expectedSchedules,
    claudeRequestBody,
  }
};

// ============================================================================
// PROCESS CLAUDE DETECTION RESPONSE
// Handles Anthropic Messages API response format from HTTP Request node
// ============================================================================

const prepData = $('Prepare Detection Prompt').first().json;
const claudeResponse = $input.first().json;

// Anthropic Messages API returns { content: [{ type: 'text', text: '...' }] }
const responseText = claudeResponse.content?.[0]?.text || claudeResponse.text || '';

if (!responseText) {
  throw new Error('Empty response from Claude API. Response: ' + JSON.stringify(claudeResponse).substring(0, 500));
}

let jsonStr = responseText.trim();

// Strip markdown code fences if present
if (jsonStr.includes('```json')) {
  jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
} else if (jsonStr.includes('```')) {
  jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
}

if (!jsonStr.startsWith('{')) {
  const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonStr = jsonMatch[0];
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(
    'Failed to parse Claude response as JSON: ' + e.message +
    '. Response preview: ' + responseText.substring(0, 500)
  );
}

const VALID_TYPES = [
  'scope_of_work', 'pricing', 'service_levels', 'data_processing',
  'governance', 'exit_transition', 'insurance', 'change_control',
  'disaster_recovery', 'security', 'benchmarking', 'subcontracting', 'other'
];

const detected = (parsed.detected_schedules || []).map(s => ({
  schedule_type: VALID_TYPES.includes(s.schedule_type) ? s.schedule_type : 'other',
  schedule_label: s.schedule_label || s.label || 'Unknown Schedule',
  start_position: s.start_char || s.start_position || null,
  end_position: s.end_char || s.end_position || null,
  confidence_score: Math.max(0, Math.min(1, s.confidence || 0.5)),
  summary: s.summary || null,
  detection_method: 'ai',
  status: 'detected',
}));

const missing = (parsed.missing_expected || []).map(m => ({
  schedule_type: m.schedule_type,
  schedule_label: m.schedule_label || m.label,
  is_required: m.is_required || false,
  reason: m.reason || 'Not found in document',
}));

console.log('Detected schedules:', detected.length);
console.log('Missing expected:', missing.length);

return {
  json: {
    contractId: prepData.contractId,
    detectedSchedules: detected,
    missingExpected: missing,
    detectionSummary: parsed.detection_summary || `Found ${detected.length} schedule(s). ${missing.filter(m => m.is_required).length} required schedule(s) missing.`,
    scheduleCount: detected.length,
  }
};

parameters.query:
-- Delete any previous detection results for this contract
DELETE FROM contract_schedules WHERE contract_id = $1::uuid;

-- Insert detected schedules
{{ $json.detectedSchedules.length > 0 ? $json.detectedSchedules.map(s => `INSERT INTO contract_schedules (contract_id, schedule_type, schedule_label, detection_method, confidence_score, start_position, end_position, summary, status) VALUES ('${$json.contractId}', '${s.schedule_type}', '${s.schedule_label.replace(/'/g, "''")}', '${s.detection_method}', ${s.confidence_score}, ${s.start_position || 'NULL'}, ${s.end_position || 'NULL'}, '${(s.summary || '').replace(/'/g, "''")}', '${s.status}');`).join('\n') : '-- No schedules detected' }}

-- Update contract metadata
UPDATE uploaded_contracts
SET schedule_count = {{ $json.scheduleCount }},
    schedule_detection_status = 'complete'
WHERE contract_id = '{{ $json.contractId }}'::uuid;
